CommonData.BannerCustomCSS:
@media only screen and (min-width: 890px){
   #onetrust-banner-sdk #onetrust-button-group{
       margin-bottom: 0.25em!important;
       margin-top: 0.25em!important;
   }
   #onetrust-banner-sdk #onetrust-button-group button{
       width: 100%!important;
       margin-bottom: 5px!important;
       margin-top: 5px!important;
   }
   #onetrust-banner-sdk #onetrust-button-group-parent{
       padding-left: 3%!important;
   }
}
@media only screen and (min-width: 426px) and (max-width: 896px){
   #onetrust-banner-sdk #onetrust-button-group-parent button{
       float: none!important;
   }
}
@media only screen and (min-width: 1024px){
   #onetrust-banner-sdk.vertical-align-content #onetrust-button-group-parent{
       width: 35%!important;
       position: initial!important;
       transform: none!important;
   }
}
/*text link style*/
#onetrust-pc-btn-handler{
    padding-top: 5px!important;
    padding-bottom: 5px!important;
}
/*button style*/
@media only screen and (min-width: 1280px) {
    #onetrust-banner-sdk:not(.ot-iab-2) #onetrust-button-group-parent {
        width: 30%!important;
        float: right;
        margin-right: 8%!important;
    }
}
@media only screen and (min-width: 897px) {
    #onetrust-banner-sdk.ot-buttons-fw:not(.ot-iab-2) #onetrust-button-group-parent {
        margin-left: 4%!important;
    }
}

CommonData.PCCustomCSS:
/* .ot-pc-footer-logoクラスを持つ要素を強制的に非表示にする */
.ot-pc-footer-logo {
    display: none !important;
}
/* .ot-pc-footer-logoクラス内のすべてのリンクを強制的に無効化する */
.ot-pc-footer-logo a {
    pointer-events: none !important; /* リンクのクリックを強制的に無効化 */
    color: inherit !important; /* リンクの色を通常のテキストと同じにし、他のスタイルから優先して適用 */
}
/* .ot-lst-subhdクラスを持つ要素を強制的に非表示にする */
.ot-lst-subhd {
    display: none !important;
}
/*SearchBox style*/
#onetrust-pc-sdk .ot-lst-subhdr {
    display: none!important;
}
